import { Component } from "react";
import { RouteComponentProps, withRouter } from "react-router-dom";
import styled from "styled-components";

import { ITranslatableComponent, SupportedLanguages, TranslatableText } from "../utilities/Types";

interface ILanguageSelectProps extends RouteComponentProps<{}>, ITranslatableComponent
{
    
}

interface ILanguageSelectState
{
    
}

class LanguageSelect extends Component<ILanguageSelectProps, ILanguageSelectState>
{
    constructor(props : ILanguageSelectProps)
    {
        super(props);
        this.state = 
        {
            
        }
        
        this.onChange = this.onChange.bind(this);
    }

    onChange(event : any)
    {
        const newValue = event.target.value;
        this.props.history.push(`/${newValue}`);
    }
    
    getOptions()
    {
        let options : Array<JSX.Element> = [];
        
        for(const language in SupportedLanguages)
        {
            const option = <option value={language} key={language}>{language}</option>;
            options.push(option);
        }
        
        return options;
    }
    
    render() : JSX.Element
    {
        const { language, translate } = this.props;
        
        const title : TranslatableText = 
        {
            sk : "Jazyk:",  
            en : "Language:"
        };
        
        return (
            <Container className="no-print">
                <Label htmlFor="language">{translate(title)}</Label>
                <select name="language" onChange={this.onChange} value={language}>
                    { this.getOptions() }
                </select>
            </Container>
        );
    }
}

const Container = styled.div`
    position: fixed;
    left: 50%;
    bottom: 0;
    
    margin: 10px;
    padding: 10px 50px;
    
    color: ${props => props.theme.color.background};
    
    border-radius: 5px;
    background-color: ${props => props.theme.color.primary.normal};
    
    transform: translateX(-50%); 
`;

const Label = styled.label`
    margin-right: 5px;
`;

export default withRouter(LanguageSelect);