import { Component } from "react";
import styled from "styled-components";

import { ILanguage, ISectionComponent, LanguageProficiency, TranslatableText } from "../../utilities/Types";
import Section from "../Section";

interface ILanguageSkillsProps extends ISectionComponent<ILanguage>
{
    
}

interface ILanguageSkillsState
{
    
}

class LanguageSkills extends Component<ILanguageSkillsProps, ILanguageSkillsState>
{
    languageProficiencyText : { [language in LanguageProficiency] : TranslatableText } = 
    {
        A1 : 
        {
            sk : "začiatočník",
            en : "beginner"
        },
        A2 : 
        {
            sk : "začiatočník",
            en : "elementary"
        },
        B1 : 
        {
            sk : "stredne pokročilý",
            en : "intermidiate"
        },
        B2 : 
        {
            sk : "stredne pokročilý",
            en : "upper intermidiate"
        },
        C1 : 
        {
            sk : "pokročilý",
            en : "advanced"
        },
        C2 : 
        {
            sk : "pokročilý",
            en : "mastery"
        },
        MOTHER_TONGUE : 
        {
            sk : "materinský jazyk",
            en : "mother tongue"
        }
    };
    
    constructor(props : ILanguageSkillsProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    getLanguageProficiency()
    {
        // let
    }
    
    getLanguageListItems()
    {
        const { data, translate } = this.props;
        
        return data.map(
            (language) =>
            {
                return (
                    <ListItem key={translate(language.name)}>
                        <Language>
                            <LanguageName>{translate(language.name)}</LanguageName>
                            <LanguageDetails>
                                <LanguageProficiencyText>{translate(this.languageProficiencyText[language.proficiency])}</LanguageProficiencyText> ({language.proficiency})
                            </LanguageDetails>
                        </Language>
                    </ListItem>
                );
            }
        );
    }

    render() : JSX.Element
    {
        const { language, translate } = this.props;
        
        const title : TranslatableText = 
        {
            sk : "Jazykové znalosti",
            en : "Language skills"
        };
        
        return (
            <Section language={language} translate={translate} icon="language" title={title}>
                <ul>
                    {this.getLanguageListItems()}
                </ul>
            </Section>
        );
    }
}

const ListItem = styled.li`
    margin-bottom: 10px;
`;

const Language = styled.div`
    display: flex;
`;
    
const LanguageName = styled.span`
    width: 150px;
`;

const LanguageDetails = styled.div`
    /* display: flex; */
    /* flex-direction: column; */
`;

const LanguageProficiencyText = styled.span`
    font-style: italic;
`;

export default LanguageSkills;