import { Component } from "react";
import styled from "styled-components";
import { EmptySection } from "../data/Translations";
import { ITranslatableComponent, TranslatableText } from "../utilities/Types";
import MaterialIcon from "./MaterialIcon";


interface ISectionProps extends ITranslatableComponent
{
    icon : string
    title : TranslatableText
}

interface ISectionState
{
    
}

class Section extends Component<ISectionProps, ISectionState>
{
    constructor(props : ISectionProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }

    render() : JSX.Element
    {
        const { icon, title, translate, children } = this.props;
        
        return (
            <Container>
                <Heading>
                    <StyledIcon icon={icon} size="34px"/>
                    <Text>{translate(title)}</Text>
                </Heading>
                
                <Content>
                    {children ? children : translate(EmptySection)}
                </Content>
            </Container>
        );
    }
}

const Container = styled.section`
    margin-bottom: 10px;
`;

const StyledIcon = styled(MaterialIcon)`
    margin: 10px;
`;

const Heading = styled.h2`
    display: flex;
    align-items: center;
    
    margin: 0 0 0px 0;
`;

const Text = styled.span`
    position: relative;
    
    &:after
    {
        content: "";
        
        position: absolute;
        left: 0;
        bottom: -5px;
        
        height: 2px;
        width: 300px;
        
        background: ${props => props.theme.color.primary.normal};
    }
`;

const Content = styled.div`
    margin-left: 60px;
`;
export default Section;