import { Component } from "react";
import styled from "styled-components";

import { ISectionComponent, ITechnicalSkills, TranslatableText } from "../../utilities/Types";
import Section from "../Section";

interface ITechnicalSkillsProps extends ISectionComponent<ITechnicalSkills>
{
    
}

interface ITechnicalSkillsState
{
    
}

class TechnicalSkills extends Component<ITechnicalSkillsProps, ITechnicalSkillsState>
{
    constructor(props : ITechnicalSkillsProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    getTechnicalSkills(data : Array<ITechnicalSkills>)
    {
        const { translate } = this.props;
        
        return data.map(
            (category) =>
            {
                return (
                    <Category key={translate(category.name)}>
                        <h3>{translate(category.name)}</h3>
                        <ul>
                            {
                                this.getTechnicalSkillsListItems(category)
                            }
                        </ul>
                    </Category>
                    
                );
            }
        );
    }
    
    getTechnicalSkillsListItems(category : ITechnicalSkills)
    {
        return category.skills.map(
            (skill) =>
            {
                return (
                    <SkillItem key={skill.name}>
                        {skill.name}
                    </SkillItem>
                );
            }
        );
    }
    
    render() : JSX.Element
    {
        const { data, language, translate } = this.props;
        
        const title : TranslatableText = 
        {
            sk : "Technické znalosti",
            en : "Technical skills"
        };
        
        return (
            <Section language={language} translate={translate} icon="code" title={title}>
                <Content>
                    { this.getTechnicalSkills(data) }
                </Content>
            </Section>
        );
    }
}

const Content = styled.div`
    display: flex;
    flex-wrap: wrap;
`;

const Category = styled.div`
    margin-right: 30px;
`;

const SkillItem = styled.li`
    margin-bottom: 10px;
`;

export default TechnicalSkills;