import React, { Component } from "react";
import styled from "styled-components";
import Section from "../Section";
import { ISchool, ISectionComponent, TranslatableText } from "../../utilities/Types";


interface IEducationProps extends ISectionComponent<ISchool>
{
    
}

interface IEducationState
{
    
}

class Education extends Component<IEducationProps, IEducationState>
{
    constructor(props : IEducationProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    getEducationListItems()
    {
        const { data , translate } = this.props;
        
        return data.map(
            (school) =>
            {
                return (
                    <ListItem key={translate(school.name)}>
                        <School>
                            <SchoolYears>{school.attendanceYears.start} - {school.attendanceYears.end}</SchoolYears>
                            <SchoolDetails>
                                <SchoolName>{translate(school.name)}</SchoolName>
                                <SchoolFaculty>{translate(school.faculty)}</SchoolFaculty>
                                <SchoolProgram>{translate(school.program)}</SchoolProgram>
                            </SchoolDetails>
                        </School>
                    </ListItem>
                );
            }
        );
    }

    render() : JSX.Element
    {
        const { language, translate } = this.props;
        
        const title : TranslatableText = 
        {
            sk : "Vzdelanie",
            en : "Education",
        };
        
        return (
            <Section language={language} translate={translate} icon="school" title={title}>
                <ul>
                    {this.getEducationListItems()}
                </ul>
            </Section>
        );
    }
}

const ListItem = styled.li`
    margin-bottom: 15px;
`;

const School = styled.div`
    display: flex;
`;
    
const SchoolYears = styled.span`
    width: 150px;
`;

const SchoolDetails = styled.div`
    display: flex;
    flex-direction: column;
`;

const SchoolName = styled.span`
    font-weight: 700;
`;

const SchoolFaculty = styled.span`
    font-style: italic;
`;

const SchoolProgram = styled.span`
    font: "Roboto Thin";
`;

export default Education;