import { Component } from 'react';
import { ThemeProvider } from 'styled-components';
import { Route, Switch } from 'react-router-dom';

import "./styles/App.scss";
import GlobalStyle from "./styles/GlobalStyle";
import { lightTheme } from './styles/Themes';

import Resume from './pages/Resume';
import { person } from "./data/Person";
import { SupportedLanguages } from './utilities/Types';
import { defaultLanguage } from './utilities/Settings';

interface IAppState
{
    
}

class App extends Component<{}, IAppState>
{
    constructor(props : {})
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    componentDidMount()
    {
        document.title = `Resume - ${person.name} ${person.surname}`;
    }
    
    getRoutes()
    {
        let routes : Array<JSX.Element> = [];
        
        for(const language in SupportedLanguages)
        {
            const route = <Route path={`/${language}`} render={ (props) => <Resume language={language as SupportedLanguages} person={person}/>} key={language}/>;
            routes.push(route);
        }
        
        const defaultRoute = <Route path={`/`} render={ (props) => <Resume language={defaultLanguage} person={person}/>} key={defaultLanguage}/>;
        routes.push(defaultRoute);
        
        return routes;
    }
    
    render() : JSX.Element
    {
        return (
            <ThemeProvider theme={lightTheme}>
                <Switch>
                    { this.getRoutes() }
                </Switch>
                
                <GlobalStyle/>
            </ThemeProvider>
        );
    }
}

export default App;