import { Component } from "react";
import styled from "styled-components";

import { IPersonalInformation } from "../utilities/Types";
import MaterialIcon, { MaterialIconsType } from "./MaterialIcon";

interface IPersonalInformationProps extends IPersonalInformation
{
    className? : string
}

interface IPersonalInformationState
{
    
}

class PersonalInformation extends Component<IPersonalInformationProps, IPersonalInformationState>
{
    icons : IPersonalInformation = 
    {
        address : "home",
        phoneNumber : "phone",
        emailAddress : "alternate_email",
        birthday : "cake"
    }
    
    constructor(props : IPersonalInformationProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    getIconComponent(icon : string)
    {
        return <MaterialIcon icon={icon} color="background" size="25px" type={MaterialIconsType.OUTLINED}/>;
    }
    
    getItemComponent(propName : keyof IPersonalInformation)
    {
        let icon : string = this.icons[propName] ? this.icons[propName] : "";
        let prop : string | undefined = this.props[propName];
        
        return <Item key={propName}>{this.getIconComponent(icon)}{prop}</Item>;
    }
    
    getItemComponents()
    {
        let components : Array<JSX.Element> = [];
              
        for(const key in this.props)
        {
            if(key === "children" || key === "className") continue;
            let component = this.getItemComponent(key as keyof IPersonalInformation);
            components.push(component);
        }
        
        return components;
    }
    
    render() : JSX.Element
    {
        const { className } = this.props;
        
        return (
            <Container className={className}>
                {this.getItemComponents()}
            </Container>
        );
    }
}

const Container = styled.div`
    display: flex;
    flex-direction: column;
`;

const Item = styled.div`
    display: flex;
    align-items: center;
    
    color: ${props => props.theme.color.background};
`;

// const StyledIcon = styled(MaterialIcon)`
    
// `;

export default PersonalInformation;