import { defaultLanguage } from "./Settings";
import { SupportedLanguages, TranslatableText } from "./Types";


export function getTranslatedText( translatableText : TranslatableText | undefined, language? : SupportedLanguages )
{
    if(!translatableText) return "";
    
    if(language) return translatableText[language];
    
    return translatableText[defaultLanguage];
}