import { Component } from "react";

import { IPerson, SupportedLanguages, TranslatableText } from "../utilities/Types";
import Header from "../components/Header";
import Education from "../components/sections/Education";
import LanguageSkills from "../components/sections/LanguageSkills";
import WorkExperience from "../components/sections/WorkExperience";
import TechnicalSkills from "../components/sections/TechnicalSkills";
import styled from "styled-components";
import { getTranslatedText } from "../utilities/Helpers";
import PrintButton from "../components/PrintButton";
import LanguageSelect from "../components/LanguageSelect";

interface IResumeProps
{
    person : IPerson
    language : SupportedLanguages
}

interface IResumeState
{
    
}

class Resume extends Component<IResumeProps, IResumeState>
{
    constructor(props : IResumeProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }
    
    translate = (text : TranslatableText | undefined) => getTranslatedText(text, this.props.language);

    render() : JSX.Element
    {
        const { person , language } = this.props;
        
        const translateProps = 
        {
            language : language,
            translate : this.translate
        }
        
        return (
            <div>
                <Header name={person.name} surname={person.surname} {...person.personalInformation}/>
                <Content>
                    <Education data={person.education} {...translateProps}/>
                    <WorkExperience data={person.workExperience} {...translateProps}/>
                    <LanguageSkills data={person.languageSkills} {...translateProps}/>
                    <TechnicalSkills data={person.technicalSkills} {...translateProps}/>
                </Content>
                
                <LanguageSelect {...translateProps}/>
                <PrintButton fileName={`${person.surname}-${person.name}_Resume_${language}`}/>
            </div>
        );
    }
}

const Content = styled.div`
    margin: 20px;
`;

export default Resume;