export enum SupportedLanguages
{
    sk = "sk",
    en = "en",
}

export type TranslatableText = {
    [language in SupportedLanguages]: string;
};

export interface ITranslatableComponent
{
    language : SupportedLanguages
    translate : (text : TranslatableText | undefined) => string
};

export interface ISectionComponent<T> extends ITranslatableComponent
{
    data : Array<T>
};

export interface IPerson
{
    name : string
    surname : string
    personalInformation : IPersonalInformation
    education : Array<ISchool>
    workExperience : Array<IWorkExperience>
    languageSkills : Array<ILanguage>
    technicalSkills : Array<ITechnicalSkills>
}

//#region Personal information

export interface IPersonalInformation
{
    address : string
    phoneNumber : string
    emailAddress : string
    birthday : string
}

//#endregion

//#region Education

export interface ISchool
{
    name : TranslatableText
    faculty? : TranslatableText
    program? : TranslatableText
    attendanceYears : 
    {
        start : string
        end : string
    }
}

//#endregion

export interface IWorkExperience
{
    
}

//#region Language skills

export enum LanguageProficiency
{
    A1 = "A1",
    A2 = "A2",
    B1 = "B1",
    B2 = "B2",
    C1 = "C1",
    C2 = "C2",
    MOTHER_TONGUE = "MOTHER_TONGUE"
}

export interface ILanguage
{
    name : TranslatableText
    proficiency : LanguageProficiency
}

//#endregion

//#region Technical skills

export interface ITechnicalSkills
{
    name : TranslatableText,
    skills : Array<ITechnicalSkill>
}

export interface ITechnicalSkill
{
    name : string
}

//#endregion