import { Component } from 'react';
import styled from 'styled-components';

import { IPersonalInformation } from '../utilities/Types';
import PersonalInformation from './PersonalInformation';

interface IHeaderProps extends IPersonalInformation
{
    name : string
    surname : string
}

interface IHeaderState
{
    
}

class Header extends Component<IHeaderProps, IHeaderState>
{
    constructor(props : IHeaderProps)
    {
        super(props);
        this.state = 
        {
            
        }
    }

    render() : JSX.Element
    {
        const { name, surname, address, phoneNumber, emailAddress, birthday } = this.props;
        
        return (
            <Container>
                <Heading>{name} {surname}</Heading>
                <StyledPersonalInformation address={address} phoneNumber={phoneNumber} emailAddress={emailAddress} birthday={birthday}/>
            </Container>
        );
    }
}

const Container = styled.header`
    position: relative;
    display: flex;
    align-items: center;
    
    padding: 25px;
    
    background-color: ${props => props.theme.color.primary.normal};
`;

const Heading = styled.h1`
    flex: 6;
    margin-left: 50px;
    
    color: ${props => props.theme.color.background};
    font-size: 50px;
    font-family: "Bebas Neue";
    letter-spacing: 2px;
`;

const StyledPersonalInformation = styled(PersonalInformation)`
    position: absolute;
    right: 25px;
`;

export default Header;